    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        long long root_u = find(u);
        long long root_v = find(v);

        if (root_u != root_v) {
            union_sets(root_u, root_v);
            components--;
            max_edge[root_u] = max(max_edge[root_u], max_edge[root_v], w);
        }
    }

    // We need to split the graph into at most k components
    // So we need to find the k-th maximum edge weight in the max_edge array
    // Sort the max_edge array and select the (k-1)-th element
    vector<long long> max_edges;
    for (long long i = 0; i < n; ++i) {
        max_edges.push_back(max_edge[i]);
    }

    sort(max_edges.begin(), max_edges.end(), greater<long long>());
    return max_edges[k - 1];
}
